export function parseProgrammeHTML(htmlString) {
  const parser = new DOMParser();
  const doc = parser.parseFromString(htmlString, "text/html");

  const programme = {
    name: "",
    weeks: []
  };

  const title = doc.querySelector(".cover-prog-name");
  if (title) {
    programme.name = title.textContent.trim();
  }

  const weekBlocks = doc.querySelectorAll(".week-block");

  weekBlocks.forEach((weekEl, wIndex) => {
    const week = {
      name: `Semaine ${wIndex + 1}`,
      sessions: []
    };

    const seances = weekEl.querySelectorAll(".seance-block");

    seances.forEach((seanceEl, sIndex) => {
      const session = {
        name: `Séance ${sIndex + 1}`,
        exercises: []
      };

      const exercises = seanceEl.querySelectorAll(".exercise-item");

      exercises.forEach((exEl, eIndex) => {
        const inputs = exEl.querySelectorAll("input");

        const exercise = {
          name: inputs[0]?.value || `Exercice ${eIndex + 1}`,
          sets: inputs[1]?.value || "",
          reps: inputs[2]?.value || "",
          rest: inputs[3]?.value || "",
          weight: ""
        };

        session.exercises.push(exercise);
      });

      week.sessions.push(session);
    });

    programme.weeks.push(week);
  });

  return programme;
}
